{
  "summary": "This paper proposes knowledge unlearning, a post hoc method using unlikelihood training to selectively forget sensitive token sequences in pretrained language models, mitigating privacy risks without full retraining. The approach introduces novel privacy risk metrics and demonstrates effective forgetting with minimal or even improved general language model performance across benchmarks.",
  "strengths": [
    {
      "point": "Efficient post hoc forgetting method",
      "evidence": "Knowledge unlearning avoids costly retraining by applying unlikelihood training to forget specific sequences, achieving approximately 3,500,000 times computational efficiency over retraining."
    },
    {
      "point": "Strong empirical privacy guarantees with minimal performance loss",
      "evidence": "The method reduces extraction likelihood and memorization accuracy for target sequences while maintaining or improving LM performance on 9 diverse NLP benchmarks."
    },
    {
      "point": "Sequential unlearning strategy improves stability",
      "evidence": "Sequentially forgetting small chunks of data is shown to be more effective and less damaging to LM performance than batch unlearning."
    },
    {
      "point": "Introduction of novel privacy risk metrics",
      "evidence": "Extraction Likelihood (EL) and Memorization Accuracy (MA) metrics are proposed to quantify privacy risks and define empirical forgetting thresholds."
    },
    {
      "point": "Analysis of domain and scale effects on unlearning",
      "evidence": "The paper shows that structured data is easier to forget than unstructured data, and larger models require fewer epochs to forget, providing insights into factors affecting unlearning difficulty."
    },
    {
      "point": "Open source release",
      "evidence": "Code and datasets are provided to facilitate replication and further research."
    }
  ],
  "weaknesses": [
    {
      "point": "Limited comparison to related unlearning techniques",
      "evidence": "The paper lacks discussion and empirical comparison with recent selective forgetting methods such as influence functions, gradient surgery, or fine-tuning with forgetting objectives."
    },
    {
      "point": "Insufficient theoretical justification and ablation of unlikelihood objective",
      "evidence": "No exploration of alternative forgetting objectives or analysis of unlikelihood loss weight, schedule, or convergence criteria is provided."
    },
    {
      "point": "Underexplored sequential unlearning design choices",
      "evidence": "No ablation on chunk size or sequence prioritization is presented, despite their practical importance."
    },
    {
      "point": "Limited and not fully comparable baselines",
      "evidence": "Baselines are restricted to data deduplication with OPT models differing in architecture and scale, lacking comparisons to fine-tuning with DP, knowledge distillation, or retraining on sanitized data."
    },
    {
      "point": "Extraction Likelihood metric lacks external validation",
      "evidence": "No user studies or adversarial attack benchmarks confirm EL’s correlation with actual privacy leakage."
    },
    {
      "point": "Empirical forgetting thresholds lack theoretical grounding",
      "evidence": "No sensitivity analysis or robustness checks across datasets, models, or privacy requirements are provided."
    },
    {
      "point": "Limited diversity of target data for forgetting",
      "evidence": "Experiments focus mainly on emails, code, and journal reviews, omitting conversational, social media, or multilingual data."
    },
    {
      "point": "Downstream task impact analysis is missing",
      "evidence": "No investigation of whether unlearning domain-specific sequences disproportionately affects related downstream tasks."
    },
    {
      "point": "Reproducibility hindered by missing hyperparameter and attack details",
      "evidence": "Key unlikelihood training hyperparameters and extraction attack implementation details are not fully described."
    },
    {
      "point": "Presentation of EL metric is confusing",
      "evidence": "The formal definition is convoluted and lacks illustrative examples, making comprehension difficult."
    },
    {
      "point": "No discussion of potential negative side effects",
      "evidence": "Risks such as unintended forgetting, bias introduction, or model calibration degradation are unaddressed."
    },
    {
      "point": "Scalability to very large models and real-world data not discussed",
      "evidence": "Challenges of applying unlearning to models with hundreds of billions of parameters or complex private data are not considered."
    },
    {
      "point": "Generalisability beyond English and Pile dataset is limited",
      "evidence": "No evaluation or discussion on multilingual or domain-specific corpora."
    },
    {
      "point": "Handling of dynamic or continuous privacy requests is unexplored",
      "evidence": "No analysis of repeated unlearning requests’ impact on model stability or cumulative performance degradation."
    }
  ],
  "questions": [
    {
      "question": "How does knowledge unlearning compare empirically and theoretically to other selective forgetting methods such as influence functions or gradient surgery?",
      "motivation": "Understanding relative advantages and limitations is critical to position the method within the broader unlearning literature."
    },
    {
      "question": "How robust and generalizable are the empirical forgetting thresholds for EL and MA across different datasets, model architectures, and privacy requirements?",
      "motivation": "Robust thresholds are essential for practical deployment and reliable privacy guarantees."
    },
    {
      "question": "What are the effects of repeated or continuous unlearning requests on model stability and cumulative performance?",
      "motivation": "Real-world privacy compliance often requires dynamic forgetting over time, so understanding long-term impacts is important."
    },
    {
      "question": "Can the EL metric be validated against external adversarial extraction attacks or user studies to confirm its practical utility?",
      "motivation": "Validation would strengthen confidence in EL as a reliable privacy risk indicator."
    },
    {
      "question": "How does unlearning affect downstream tasks related to the forgotten data domain?",
      "motivation": "Task-specific impacts could reveal trade-offs between privacy and utility."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
